import React, { useState, useEffect, useRef } from 'react';
import { useSelector, useDispatch } from 'react-redux';  // ← Redux хуки
import Graph from './Graph';
import { pointAPI, authAPI } from './api';
import { setPoints, addPoint, clearPoints, setLoading, setError } from './store/pointsSlice';
import { logout as logoutAction } from './store/authSlice';

function MainPage({ onLogout }) {
  // Используем Redux состояние вместо локального!
  const points = useSelector(state => state.points.items);
  const loading = useSelector(state => state.points.loading);
  const pointsError = useSelector(state => state.points.error);
  const auth = useSelector(state => state.auth);

  const dispatch = useDispatch();

  // Локальное состояние только для формы
  const [x, setX] = useState('');
  const [y, setY] = useState('');
  const [r, setR] = useState('');
  const [formError, setFormError] = useState('');  // ← Переименовали, чтобы не конфликтовало
  const [username, setUsername] = useState('');

  const xOptions = [-5, -4, -3, -2, -1, 0, 1, 2, 3];
  const rOptions = [-5, -4, -3, -2, -1, 0, 1, 2, 3];

  // Загружаем результаты при загрузке
  const resultsLoaded = useRef(false);

  useEffect(() => {
    if (!resultsLoaded.current) {
      loadResults();
      resultsLoaded.current = true;
    }

    // Используем имя из Redux store
    if (auth.username) {
      setUsername(auth.username);
    } else {
      // Или из localStorage как fallback
      const savedUsername = localStorage.getItem('username');
      if (savedUsername) {
        setUsername(savedUsername);
      }
    }
  }, [auth.username]);  // ← Следим за изменением в Redux store

  const loadResults = async () => {
    if (loading) return;  // Уже загружаем

    dispatch(setLoading(true));
    try {
      const result = await pointAPI.getResults();
      if (result.success) {
        dispatch(setPoints(result.data));  // ← Сохраняем в Redux!
      } else {
        dispatch(setError(result.message));
        setFormError(result.message);
      }
    } catch (err) {
      dispatch(setError('Ошибка загрузки данных'));
      setFormError('Ошибка загрузки данных');
    } finally {
      dispatch(setLoading(false));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setFormError('');

    if (!x || y === '' || !r) {
      setFormError('Заполните все поля');
      return;
    }

    const xNum = parseFloat(x);
    const yNum = parseFloat(y);
    const rNum = parseFloat(r);

    // Валидация X (-5..3)
    if (!xOptions.includes(xNum)) {
      setFormError('X должен быть одним из: ' + xOptions.join(', '));
      return;
    }

    // Валидация Y (-5..3)
    if (isNaN(yNum) || yNum < -5 || yNum > 3) {
      setFormError('Y должен быть числом от -5 до 3');
      return;
    }

    // Валидация R (-5..3, но с проверкой в бэкенде)
    if (!rOptions.includes(rNum)) {
      setFormError('R должен быть одним из: ' + rOptions.join(', '));
      return;
    }

    // Дополнительная проверка: радиус не может быть ≤ 0
    if (rNum <= 0) {
      setFormError('Радиус R должен быть положительным числом');
      return;
    }

    dispatch(setLoading(true));
    try {
      const result = await pointAPI.checkPoint(xNum, yNum, rNum);

      if (result.success) {
        dispatch(addPoint(result.data));  // ← Добавляем в Redux!
        setY('');  // Очищаем только Y поле
      } else {
        setFormError(result.message);
        dispatch(setError(result.message));
      }
    } catch (err) {
      setFormError('Ошибка соединения с сервером');
      dispatch(setError('Ошибка соединения с сервером'));
    } finally {
      dispatch(setLoading(false));
    }
  };

  const handleClearResults = async () => {
    if (window.confirm('Вы уверены, что хотите очистить историю?')) {
      try {
        const result = await pointAPI.clearResults();
        if (result.success) {
          dispatch(clearPoints());  // ← Очищаем Redux store
        }
      } catch (err) {
        dispatch(setError('Ошибка очистки данных'));
      }
    }
  };

  const handleLogout = async () => {
    try {
      await authAPI.logout();
    } catch (err) {
      // Игнорируем ошибки логаута
    }

    // Диспатчим action логаута
    dispatch(logoutAction());

    // Вызываем callback из App.js
    onLogout();
  };

  const handleCanvasClick = async (clickX, clickY) => {
    if (!r) {
      setFormError('Сначала выберите радиус R');
      return;
    }

    const result = await pointAPI.checkPoint(clickX, clickY, parseFloat(r));
    if (result.success) {
      dispatch(addPoint(result.data));  // ← Добавляем в Redux!
    } else {
      setFormError(result.message);
    }
  };

  return (
    <div className="main-container">
      <header className="header">
        <div>
          <h1>Проверка попадания точки в область</h1>
          <p>Пользователь: {username}</p>
          {auth.isAuthenticated && (
            <p style={{ fontSize: '12px', color: '#27ae60' }}>
              ✓ Аутентифицирован через Redux
            </p>
          )}
        </div>
        <button onClick={handleLogout} className="logout-btn">
          Выйти
        </button>
      </header>

      <div className="content">
        <div className="form-section">
          <form onSubmit={handleSubmit} className="point-form">
            <h2>Введите координаты</h2>

            {/* X: selectOneMenu */}
            <div className="form-group">
              <label>Координата X (select):</label>
              <select
                value={x}
                onChange={(e) => setX(e.target.value)}
                className="form-select"
                disabled={loading}
              >
                <option value="">Выберите X</option>
                {xOptions.map(value => (
                  <option key={value} value={value}>
                    {value}
                  </option>
                ))}
              </select>
            </div>

            {/* Y: inputText */}
            <div className="form-group">
              <label htmlFor="y">Координата Y (input):</label>
              <input
                type="number"
                id="y"
                value={y}
                onChange={(e) => setY(e.target.value)}
                placeholder="-5 ... 3"
                min="-5"
                max="3"
                step="0.1"
                className="form-input"
                disabled={loading}
              />
              <small>Диапазон: от -5 до 3</small>
            </div>

            {/* R: selectBooleanCheckBox (radio buttons) */}
            <div className="form-group">
              <label>Радиус R (radio):</label>
              <div className="radio-group">
                {rOptions.map(value => (
                  <label key={value} className="radio-label">
                    <input
                      type="radio"
                      name="r"
                      value={value}
                      checked={r === value.toString()}
                      onChange={(e) => setR(e.target.value)}
                      disabled={loading}
                    />
                    {value}
                  </label>
                ))}
              </div>
            </div>

            {/* Показываем ошибки из Redux И локальные */}
            {(formError || pointsError) && (
              <div className="error-message">
                {formError || pointsError}
              </div>
            )}

            {/* Показываем индикатор загрузки из Redux */}
            {loading && (
              <div className="loading-indicator">
                <span>⏳ Загрузка...</span>
              </div>
            )}

            <button
              type="submit"
              className="submit-btn"
              disabled={loading || !x || !r}
            >
              {loading ? 'Проверка...' : 'Проверить'}
            </button>
          </form>

          <div className="action-buttons">
            <button
              onClick={handleClearResults}
              className="clear-btn"
              disabled={points.length === 0 || loading}
            >
              Очистить историю
            </button>
          </div>
        </div>

        <div className="graph-section">
          {/* Передаем points из Redux в Graph */}
          <Graph
            results={points}  // ← Используем points из Redux, не results!
            currentR={r ? parseFloat(r) : null}
            onCanvasClick={handleCanvasClick}
          />

          <div className="results-section">
            <h2>История проверок (Redux: {points.length} точек)</h2>

            {/* Показываем количество точек из Redux */}
            <div style={{ marginBottom: '10px', fontSize: '14px', color: '#666' }}>
              Всего точек в Redux store: <strong>{points.length}</strong>
            </div>

            {points.length === 0 ? (
              <p className="no-results">Нет результатов. Проверьте точку!</p>
            ) : (
              <table className="results-table">
                <thead>
                  <tr>
                    <th>X</th>
                    <th>Y</th>
                    <th>R</th>
                    <th>Результат</th>
                    <th>Время</th>
                  </tr>
                </thead>
                <tbody>
                  {points.map((point, index) => (  // ← Используем points из Redux!
                    <tr
                      key={index}
                      className={point.hit ? 'hit-row' : 'miss-row'}
                    >
                      <td>{point.x.toFixed(3)}</td>
                      <td>{point.y.toFixed(3)}</td>
                      <td>{point.r}</td>
                      <td>
                        <span className={point.hit ? 'hit' : 'miss'}>
                          {point.hit ? 'Попадание' : 'Промах'}
                        </span>
                      </td>
                      <td>
                        {new Date(point.createdAt).toLocaleString('ru-RU')}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

export default MainPage;
